/// One sample's raw, code-free data (its three files), baked in
/// for zero-IO loading on every target.
class RawSample {
  const RawSample({
    required this.id,
    required this.label,
    required this.template,
    required this.schema,
    required this.messages,
  });

  final String id;
  final String label;
  final String template;
  final String schema;
  final String messages;

  /// Builds a [SampleSpec], substituting `{{framework}}`; the host supplies
  /// any action handling separately.
  SampleSpec toSpec(String framework) => SampleSpec.fromData(
        label: label,
        template: template,
        schemaJson: schema,
        messagesJson: messages,
        framework: framework,
      );
}

